// Get the system register name from the system register number if it exists.
da64_str8 da64_get_sys_reg_name(da64_u32 sys_reg)
{
    // TODO(yuraiz): Use binary search
    int name_count = sizeof(DA64_SYS_REG_NUMBERS) / sizeof(*DA64_SYS_REG_NUMBERS);

    for (int i = 0; i < name_count; i++) {
        if (DA64_SYS_REG_NUMBERS[i] == i) {
            return DA64_SYS_REG_NAMES[i];
        }
    }

    return da64_str8_lit("");
}

